The age of AI isn't coming—it's already here. As .NET developers, integrating powerful LLMs like ChatGPT or Azure OpenAI into web apps can unlock everything from smarter customer support to AI-assisted form filling and dynamic content creation.In this guide, we’ll walk through how to integrate ChatGPT (via Azure OpenAI) into your ASP.NET Core app step-by-step—with code examples, use cases, and best practices.Why Integrate AI into Your .NET Apps?Automate repetitive user tasksProvide intelligent, conversational UIGenerate content dynamicallyEnable semantic search or natural language queriesBuild intelligent agents for internal toolsASP.NET Core 6+ project (e.g., Razor Pages or Web API)Azure subscription with OpenAI resource deployedAccess to Azure OpenAI API KeyBasic knowledge of HTTP calls in .NET (HttpClient)1️⃣ Setup Azure OpenAI in Azure PortalGo to Azure Portal → Create a "Azure OpenAI" resource
Deploy a model (e.g., gpt-35-turbo, gpt-4)
Grab: Endpoint, Deployment name, API key2️⃣ Add HTTP Client in ASP.NET Coreservices.AddHttpClient("AzureOpenAI", client =>
{
    client.BaseAddress = new Uri("https://<your-resource>.openai.azure.com/");
    client.DefaultRequestHeaders.Add("api-key", "<your-api-key>");
});
3️⃣ public class ChatRequest
{
    public string Role { get; set; } = "user";
    public string Content { get; set; } = string.Empty;
}
4️⃣ Build the Chat Completion API Callpublic class OpenAIService
{
    private readonly HttpClient _client;
    private readonly string _deployment = "gpt-35-turbo";

    public OpenAIService(IHttpClientFactory factory)
    {
        _client = factory.CreateClient("AzureOpenAI");
    }

    public async Task<string> GetResponseAsync(string userPrompt)
    {
        var payload = new
        {
            messages = new[]
            {
                new { role = "user", content = userPrompt }
            },
            max_tokens = 200
        };

        var response = await _client.PostAsJsonAsync(
            $"/openai/deployments/{_deployment}/chat/completions?api-version=2023-03-15-preview",
            payload);

        response.EnsureSuccessStatusCode();
        var result = await response.Content.ReadFromJsonAsync<JsonElement>();
        return result.GetProperty("choices")[0].GetProperty("message").GetProperty("content").GetString();
    }
}

5️⃣ Create an API or Razor Page to Consume It[ApiController]
[Route("api/chat")]
public class ChatController : ControllerBase
{
    private readonly OpenAIService _openAI;

    public ChatController(OpenAIService openAI)
    {
        _openAI = openAI;
    }

    [HttpPost]
    public async Task<IActionResult> Ask([FromBody] ChatRequest request)
    {
        var reply = await _openAI.GetResponseAsync(request.Content);
        return Ok(reply);
    }
}

